const body = $input.first().json.body || $input.first().json;
const businessName = String(body.businessName || '').trim();
const industry = String(body.industry || '').trim();
const language = String(body.language || 'es-AR').trim();
const googleReviewUrl = String(body.googleReviewUrl || '').trim();
const email = String(body.email || '').toLowerCase().trim();
const password = String(body.password || '').trim();
const aiHint = String(body.aiHint || '').trim();

if (!businessName || !industry || !email || !email.includes('@') || password.length < 6) {
  throw new Error('Invalid input: businessName, industry, email and password (min 6) are required');
}

// Generate slug from businessName
let slug = businessName.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-|-$/g, '');
if (!slug) slug = 'negocio';

const emailSearchUrl = 'https://api.airtable.com/v0/appwlnvY7rceVb06Q/tblxTlomzuupQcgyY?filterByFormula=' + encodeURIComponent("{notificationEmail}='" + email + "'") + '&maxRecords=1';
const slugSearchUrl = 'https://api.airtable.com/v0/appwlnvY7rceVb06Q/tblxTlomzuupQcgyY?filterByFormula=' + encodeURIComponent("{clientId}='" + slug + "'") + '&maxRecords=1';

return [{ json: { businessName, industry, language, googleReviewUrl, email, password, aiHint, baseSlug: slug, emailSearchUrl, slugSearchUrl } }];

const records = $input.first().json.records || [];
const prev = $('Code - Validate & Slug').item.json;
return [{ json: { ...prev, emailExists: records.length > 0 } }];

const records = $input.first().json.records || [];
const prev = $('Code - Check Email Result').item.json;
let slug = prev.baseSlug;
if (records.length > 0) {
  // slug taken — append random 4-char suffix
  const suffix = Math.random().toString(36).slice(2, 6);
  slug = prev.baseSlug + '-' + suffix;
}
return [{ json: { ...prev, clientId: slug } }];

