parameters.jsCode:
const prev = $('Code - Resolve Slug').item.json;
const content = $input.first().json.choices?.[0]?.message?.content || '{}';

let aiConfig = {};
try {
  const cleaned = content.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
  aiConfig = JSON.parse(cleaned);
} catch(e) {
  // fallback defaults based on language
  const isEn = prev.language === 'en-US';
  aiConfig = {
    aiTopics: isEn ? 'customer service\nproduct quality\ncleanliness\nvalue for money' : 'buena atencion\ncalidad del producto\nlimpieza\nrelacion precio-calidad',
    aiTones: isEn ? 'enthusiastic\ncasual and friendly\nbrief and direct' : 'entusiasta\ncasual y amigable\nbreve y directo',
    aiStyles: isEn ? 'Start with what stood out most\nStart with a recommendation\nStart with how you felt' : 'Empieza por lo que mas te llamo la atencion\nEmpieza con una recomendacion\nEmpieza por como te sentiste',
    suggestedReviewText: isEn ? 'Great experience, I totally recommend it!' : 'Muy buena experiencia, lo recomiendo!'
  };
}

return [{ json: {
  ...prev,
  aiTopics: String(aiConfig.aiTopics || ''),
  aiTones: String(aiConfig.aiTones || ''),
  aiStyles: String(aiConfig.aiStyles || ''),
  suggestedReviewText: String(aiConfig.suggestedReviewText || '')
} }];
